class User {
  final String name;
  final String email;

  User(this.name, this.email);

  factory User.fromMap(Map<String, String> data) {
    return User(data['username']!, data['email']!);
  }

  String getFormatted() => 'User: $name <$email>';
}

void main() {
  var u = User.fromMap({'username': 'Bob', 'email': 'bob@dev.io'});
  print(u.getFormatted());
}
